def median(numbers: list[float]) -> float:
    if not numbers:
        raise ValueError("median of empty list is undefined")
    sorted_nums = sorted(numbers)
    n = len(sorted_nums)
    if n % 2 == 1:
        return sorted_nums[n // 2]
    return (sorted_nums[n // 2 - 1] + sorted_nums[n // 2]) / 2

def dedupe_preserving_order(items: list) -> list:
    seen = set()
    out = []
    for item in items:
        if item not in seen:
            seen.add(item)
            out.append(item)
    return out

import pytest
from mymod import parse_duration

class TestParseDuration:
    def test_hours_only(self):
        assert parse_duration('2h') == 7200

    def test_minutes_only(self):
        assert parse_duration('45m') == 2700

    def test_seconds_only(self):
        assert parse_duration('30s') == 30

    def test_hours_and_minutes(self):
        assert parse_duration('1h30m') == 5400

    def test_all_three(self):
        assert parse_duration('1h2m3s') == 3723

    def test_zero_components_ok(self):
        assert parse_duration('0h0m0s') == 0

    def test_empty_string_raises(self):
        with pytest.raises(ValueError, match='empty duration'):
            parse_duration('')

    def test_malformed_raises(self):
        with pytest.raises(ValueError, match='malformed'):
            parse_duration('abc')

    def test_wrong_order_raises(self):
        with pytest.raises(ValueError, match='malformed'):
            parse_duration('30m1h')

    def test_unit_only_no_number_raises(self):
        with pytest.raises(ValueError, match='malformed'):
            parse_duration('h')
